from __future__ import annotations

from datetime import datetime
from enum import Enum
from typing import Optional

from pydantic import BaseModel, ConfigDict, Field


class WorkflowDetails(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    name: str = Field(..., title="Workflow Name")
    description: Optional[str] = Field("", title="Workflow Description")


class LoadLocalLgFile(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    file_path: str = Field(
        ..., description="Path to the tabular file (CSV or Parquet).", title="File Path"
    )


class TimezoneInfo(BaseModel):
    label: str = Field(..., title="Label")
    tzCode: str = Field(..., title="Tzcode")
    name: str = Field(..., title="Name")
    utc: str = Field(..., title="Utc")


class TimeFrequency(str, Enum):
    Year = "Year"
    Quarter = "Quarter"
    Month = "Month"
    Week = "Week"
    Day = "Day"
    Hour = "Hour"
    Minute = "Minute"


class ValueGrouper(BaseModel):
    index_name: Optional[str] = None


class TimeRange(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    since: datetime = Field(..., description="The start time", title="Since")
    until: datetime = Field(..., description="The end time", title="Until")
    timezone: Optional[TimezoneInfo] = Field(None, title="Timezone")
    time_format: Optional[str] = Field(
        "%d %b %Y %H:%M:%S", description="The time format", title="Time Format"
    )


class TimeFrequencyModel(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    time_frequency: TimeFrequency = Field(
        ...,
        description="The time frequency to use across all time-series charts in the workflow.",
        title="Time Frequency",
    )


class FormData(BaseModel):
    model_config = ConfigDict(
        extra="forbid",
    )
    workflow_details: Optional[WorkflowDetails] = Field(
        None,
        description="Add information that will help to differentiate this workflow from another.",
        title="Set workflow details",
    )
    time_range: Optional[TimeRange] = Field(
        None,
        description="Choose the period of time to analyze.",
        title="Define analysis time range",
    )
    time_frequency: Optional[TimeFrequencyModel] = Field(
        None, title="Select time frequency for temporal charts"
    )
    load_local_lg_file: Optional[LoadLocalLgFile] = Field(
        None, title="Load local tabular file"
    )
